  ('idea-oats', 'Overnight oats protéiné', 'pdj', ARRAY['pdj']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 390, 35, null, null, 1, '[]'::jsonb, '🥣', true, '["40 g de flocons d''avoine","250 ml de lait d''amande","1 dose de Vegan Protein","une poignée de fruits rouges","1 c. à café de graines de chia"]'::jsonb, '["La veille, mélange flocons + lait + protéine + chia dans un bocal.","Laisse une nuit au frigo.","Le matin, ajoute les fruits."]'::jsonb, 'Se prépare la veille, se mange (ou se boit) en voiture.', 192),
  ('idea-pancakes', 'Pancakes protéinés', 'pdj', ARRAY['pdj']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 400, 35, null, null, 1, '[]'::jsonb, '🥞', true, '["40 g de flocons mixés","2 œufs","1 banane écrasée","1/2 dose de Vegan Protein","cannelle"]'::jsonb, '["Mixe le tout en pâte.","Cuis en petits pancakes, poêle antiadhésive sans huile.","Garnis de fruits ou d''un filet de sirop léger."]'::jsonb, 'Sans huile, à la poêle antiadhésive.', 193),
  ('idea-tofuscramble', 'Tofu brouillé express', 'pdj', ARRAY['pdj']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 290, 22, null, null, 1, '[]'::jsonb, '🍳', true, '["150 g de tofu ferme","curcuma, paprika, sel kala namak (goût œuf)","1 tranche de pain complet"]'::jsonb, '["Écrase le tofu à la fourchette.","Poêle antiadhésive + épices, 5 min.","Sers avec le pain."]'::jsonb, 'L''alternative aux œufs, goût brouillé.', 194),
  ('idea-skyrmuesli', 'Skyr soja & muesli', 'pdj', ARRAY['pdj']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 320, 20, null, null, 1, '[]'::jsonb, '🥣', true, '["150 g de skyr/yaourt soja protéiné","40 g de muesli sans sucre ajouté","fruits frais"]'::jsonb, '["Mélange skyr + muesli.","Ajoute les fruits."]'::jsonb, 'Rapide. Choisis un skyr SOJA (plus protéiné que l''amande) et un muesli sans sucre ajouté.', 195),
  ('idea-buddha', 'Buddha bowl tofu', 'dej', ARRAY['dej']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 470, 32, null, null, 1, '[]'::jsonb, '🥗', true, '["150 g de tofu fumé ou teriyaki","80 g de quinoa (cru) cuit","80 g d''edamame","crudités (carotte, chou, concombre)","sauce soja + citron + gingembre"]'::jsonb, '["Cuis le quinoa.","Poêle le tofu.","Assemble avec edamame et crudités, nappe de sauce."]'::jsonb, 'Protéiné, frais, sec en gras.', 196),
