  ('idea-steak', 'Steak végétal & légumes rôtis', 'dej', ARRAY['dej']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 450, 30, null, null, 1, '[]'::jsonb, '🥩', false, '["1 steak végétal","grosse portion de légumes rôtis","100 g de patate douce ou lentilles"]'::jsonb, '["Rôtis les légumes au four.","Poêle le steak.","Assemble."]'::jsonb, 'Avec HappyVore ou Garden Gourmet.', 198),
  ('idea-wrap', 'Wrap protéiné', 'dej', ARRAY['dej']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 400, 22, null, null, 1, '[]'::jsonb, '🌯', true, '["1 tortilla complète","jambon La Vie ou tofu","crudités","1 c. à soupe de houmous"]'::jsonb, '["Tartine le houmous.","Garnis de protéine + crudités.","Roule serré."]'::jsonb, 'À emporter, se mange à une main.', 199),
  ('idea-medbowl', 'Bowl méditerranéen', 'dej', ARRAY['dej']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 470, 26, null, null, 1, '[]'::jsonb, '🥙', true, '["150 g de pois chiches","1 œuf dur","concombre + tomate","60 g de boulgour (cru) cuit","citron, herbes"]'::jsonb, '["Cuis le boulgour.","Assemble pois chiches, œuf, légumes.","Assaisonne citron + herbes."]'::jsonb, 'Pois chiches + œuf, frais et complet.', 200),
  ('idea-curry', 'Curry de pois chiches express', 'diner', ARRAY['diner']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 520, 22, null, null, 1, '[]'::jsonb, '🍛', false, '["150 g de pois chiches","150 ml de lait de coco allégé","épinards","tomate concassée + pâte de curry","100 g de riz basmati (cru) cuit"]'::jsonb, '["Fais mijoter tomate + curry + coco.","Ajoute pois chiches et épinards, 10 min.","Sers sur le riz."]'::jsonb, 'Réconfortant, prêt en 15 min.', 201),
  ('idea-wok', 'Poêlée tofu-légumes & soba', 'diner', ARRAY['diner']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 480, 28, null, null, 1, '[]'::jsonb, '🍜', false, '["150 g de tofu teriyaki","wok de légumes (poivron, brocoli, pousses)","80 g de nouilles soba (crues) cuites","sauce soja"]'::jsonb, '["Cuis les soba.","Saute tofu + légumes au wok.","Mélange, nappe de sauce."]'::jsonb, 'Façon wok, vite fait.', 202),
