  ('idea-porridge', 'Porridge protéiné chaud', 'pdj', ARRAY['pdj']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 400, 35, null, null, 1, '[]'::jsonb, '🥣', false, '["40 g de flocons d''avoine","250 ml de lait d''amande","1 dose de Vegan Protein","1/2 banane en rondelles","cannelle"]'::jsonb, '["Cuis flocons + lait 3-4 min en remuant.","Hors du feu, incorpore la protéine.","Garnis de banane et cannelle."]'::jsonb, 'Chaud et réconfortant les matins d''hiver.', 210),
  ('idea-chia', 'Chia pudding amande', 'pdj', ARRAY['pdj']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 300, 20, null, null, 1, '[]'::jsonb, '🍮', true, '["30 g de graines de chia","250 ml de lait d''amande","1/2 dose de Vegan Protein","fruits rouges"]'::jsonb, '["Mélange chia + lait + protéine.","Repos une nuit au frigo.","Ajoute les fruits au matin."]'::jsonb, 'Se prépare la veille, ultra rassasiant.', 211),
  ('idea-toastoeuf', 'Toast œuf-avocat', 'pdj', ARRAY['pdj']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 430, 20, null, null, 1, '[]'::jsonb, '🥑', true, '["2 tranches de pain complet","1/2 avocat","2 œufs pochés ou au plat","citron, piment"]'::jsonb, '["Toaste le pain, écrase l''avocat dessus.","Cuis les œufs.","Pose-les sur le toast, citron + piment."]'::jsonb, 'Le brunch express, bon gras maîtrisé.', 212),
  ('idea-dahl', 'Dahl de lentilles corail', 'dej', ARRAY['dej']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 520, 22, null, null, 1, '[]'::jsonb, '🍛', false, '["80 g de lentilles corail (crues)","150 ml de lait de coco allégé","tomate, oignon, épices (curcuma, cumin)","60 g de riz basmati (cru) cuit"]'::jsonb, '["Fais revenir oignon + épices.","Ajoute lentilles, tomate, coco, mijote 15 min.","Sers sur le riz."]'::jsonb, 'Épicé, réconfortant, peu de gras.', 213),
  ('idea-poke', 'Poke bowl tofu', 'dej', ARRAY['dej']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 480, 28, null, null, 1, '[]'::jsonb, '🍣', true, '["80 g de riz (cru) cuit","120 g de tofu fumé en dés","edamame","concombre, carotte, oignon rouge","sauce soja + sésame"]'::jsonb, '["Dispose le riz tiède dans un bol.","Ajoute tofu, edamame et crudités.","Nappe de sauce, parsème de sésame."]'::jsonb, 'Frais, façon hawaïen.', 214),
