  ('idea-pates', 'Pâtes complètes & boulettes La Vie', 'diner', ARRAY['diner']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 520, 28, null, null, 1, '[]'::jsonb, '🍝', false, '["80 g de pâtes complètes (crues)","boulettes La Vie","sauce tomate basilic","parmesan végétal (option)"]'::jsonb, '["Cuis les pâtes.","Réchauffe boulettes dans la sauce tomate.","Mélange et sers."]'::jsonb, 'Le confort food protéiné.', 216),
  ('idea-shakshuka', 'Shakshuka', 'diner', ARRAY['diner']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 400, 22, null, null, 1, '[]'::jsonb, '🥘', false, '["3 œufs","tomate concassée, poivron, oignon","cumin, paprika","1 tranche de pain complet"]'::jsonb, '["Mijote tomate + poivron + épices.","Casse les œufs dedans, couvre 5-6 min.","Sers avec le pain pour saucer."]'::jsonb, 'Œufs pochés dans une sauce tomate-poivron.', 217),
  ('idea-tofuwok', 'Tofu teriyaki & riz sauté légumes', 'diner', ARRAY['diner']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 480, 24, null, null, 1, '[]'::jsonb, '🍚', false, '["150 g de tofu teriyaki La Vie","80 g de riz (cru) cuit","wok de légumes (poivron, brocoli, petits pois)","sauce soja"]'::jsonb, '["Saute les légumes au wok.","Ajoute le riz cuit et le tofu, fais sauter.","Déglace à la sauce soja."]'::jsonb, 'Vite fait au wok.', 218),
  ('idea-edamame', 'Edamame vapeur', 'snack', ARRAY['snack']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 190, 17, null, null, 1, '[]'::jsonb, '🫛', true, '["150 g d''edamame (dans la cosse)","sel, ou un peu de piment"]'::jsonb, '["Cuis 5 min à la vapeur ou à l''eau bouillante.","Sale et déguste en pressant les cosses."]'::jsonb, 'Le snack le plus protéiné qui soit.', 219),
  ('idea-mugcake', 'Mug cake protéiné', 'snack', ARRAY['snack']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 220, 28, null, null, 1, '[]'::jsonb, '🧁', true, '["1 dose de Vegan Protein (chocolat)","1 c. à soupe de cacao","1/2 banane écrasée","1 blanc d''œuf","1/2 c. à café de levure"]'::jsonb, '["Mélange tout dans un mug.","Micro-ondes 1 min.","Laisse tiédir 1 min avant de manger."]'::jsonb, 'Dessert chaud en 1 min au micro-ondes.', 220),
  ('idea-pommePB', 'Pomme & purée de cacahuète', 'snack', ARRAY['snack']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 180, 4, null, null, 1, '[]'::jsonb, '🍎', true, '["1 pomme en quartiers","1 c. à soupe de purée de cacahuète"]'::jsonb, '["Coupe la pomme.","Trempe dans la purée de cacahuète."]'::jsonb, 'Sucré-salé, croquant.', 221),
  ('idea-orangetofu', 'Tofu croustillant à l''orange', 'diner', ARRAY['diner']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 480, 26, null, null, 1, '[]'::jsonb, '🍊', false, '["200 g de tofu ferme en cubes","1 c. à soupe de maïzena","le jus d''1 orange","2 c. à soupe de sauce soja","1 c. à café de sirop d''érable","ail + gingembre râpés","60 g de riz (cru) cuit"]'::jsonb, '["Presse le tofu, enrobe les cubes de maïzena.","Dore-les à la poêle (peu d''huile) ou à l''airfryer jusqu''à croustillant.","Fais réduire jus d''orange + soja + sirop + ail/gingembre 3 min.","Enrobe le tofu de sauce, sers sur le riz."]'::jsonb, 'Inspirée de The Conscious Plant Kitchen. Croustillant dehors, sauce orange acidulée.', 222),
  ('idea-szechuan', 'Tofu Szechuan', 'diner', ARRAY['diner']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 500, 28, null, null, 1, '[]'::jsonb, '🌶️', false, '["200 g de tofu ferme en cubes","1 poivron + oignon","sauce : soja, vinaigre de riz, ail, piment, pointe de sucre","60 g de riz (cru) cuit"]'::jsonb, '["Dore le tofu jusqu''à croustillant.","Saute poivron + oignon au wok.","Ajoute le tofu et la sauce, fais glacer 2 min.","Sers sur le riz."]'::jsonb, 'Inspirée de The Conscious Plant Kitchen. Relevé, vite fait au wok.', 223),
  ('idea-bolo', 'Bolognaise végétale aux lentilles', 'diner', ARRAY['diner']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 520, 24, null, null, 1, '[]'::jsonb, '🍝', false, '["150 g de lentilles vertes cuites","carotte + oignon + céleri hachés","tomate concassée + herbes","80 g de pâtes complètes (crues)"]'::jsonb, '["Fais revenir carotte, oignon, céleri.","Ajoute lentilles, tomate, herbes, mijote 20 min.","Cuis les pâtes, mélange."]'::jsonb, 'Inspirée de The Conscious Plant Kitchen. La bolo réconfortante, sans viande.', 224),
  ('idea-hpsalad', 'Salade vegan hyper-protéinée', 'dej', ARRAY['dej']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 450, 35, null, null, 1, '[]'::jsonb, '🥗', true, '["80 g d''edamame","100 g de pois chiches","80 g de tofu fumé en dés","crudités + graines de courge","sauce tahini + citron + eau"]'::jsonb, '["Assemble edamame, pois chiches, tofu et crudités.","Émulsionne tahini + citron + un peu d''eau.","Nappe, parsème de graines."]'::jsonb, 'Inspirée de The Conscious Plant Kitchen. Le combo edamame + pois chiches + tofu.', 225),
  ('idea-bbburger', 'Burger patate douce & haricots noirs', 'dej', ARRAY['dej']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 430, 18, null, null, 1, '[]'::jsonb, '🍔', false, '["1 petite patate douce cuite écrasée","150 g de haricots noirs écrasés","3 c. à soupe de flocons d''avoine","épices (cumin, paprika, ail)","1 pain à burger complet + crudités"]'::jsonb, '["Mélange patate douce, haricots, flocons et épices.","Forme une galette, cuis 5 min par face à la poêle.","Sers dans le pain avec des crudités."]'::jsonb, 'Inspirée de The Conscious Plant Kitchen. Galette maison moelleuse.', 226),
  ('idea-teriyaki', 'Nouilles teriyaki & edamame', 'diner', ARRAY['diner']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 480, 22, null, null, 1, '[]'::jsonb, '🍜', false, '["80 g de nouilles (crues) cuites","80 g d''edamame","tofu teriyaki La Vie","légumes (poivron, carotte, oignon vert)","sauce teriyaki (soja, sirop, ail, gingembre)"]'::jsonb, '["Cuis les nouilles.","Saute légumes + tofu, ajoute edamame.","Ajoute nouilles + sauce, fais glacer 2 min."]'::jsonb, 'Inspirée de The Conscious Plant Kitchen. Rapide et gourmand.', 227),
  ('idea-peanutnoodles', 'Nouilles crémeuses cacahuète & tofu', 'diner', ARRAY['diner']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 540, 26, null, null, 1, '[]'::jsonb, '🥜', false, '["80 g de nouilles (crues) cuites","120 g de tofu fumé","sauce : purée de cacahuète, soja, citron vert, ail, eau","crudités râpées (carotte, chou)"]'::jsonb, '["Cuis les nouilles.","Dore le tofu.","Mélange nouilles + tofu + sauce cacahuète, parsème de crudités."]'::jsonb, 'Inspirée de The Conscious Plant Kitchen. Sauce satay onctueuse.', 228),
  ('idea-broccolipasta', 'Pâtes crémeuses au brocoli', 'diner', ARRAY['diner']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 470, 18, null, null, 1, '[]'::jsonb, '🥦', false, '["80 g de pâtes complètes (crues)","1 gros brocoli","ail, levure maltée","un peu de lait d''amande pour lier"]'::jsonb, '["Cuis pâtes + brocoli ensemble.","Mixe une partie du brocoli avec ail, levure maltée et lait d''amande.","Mélange la sauce aux pâtes."]'::jsonb, 'Inspirée de The Conscious Plant Kitchen. Sauce veloutée sans crème.', 229),
  ('idea-enchiladas', 'Enchiladas haricots noirs', 'diner', ARRAY['diner']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 450, 18, null, null, 1, '[]'::jsonb, '🫔', false, '["2 tortillas complètes","150 g de haricots noirs","maïs + poivron","sauce tomate épicée","fromage râpé (option)"]'::jsonb, '["Garnis les tortillas de haricots, maïs, poivron.","Roule-les dans un plat, nappe de sauce tomate.","Gratine 15 min au four."]'::jsonb, 'Inspirée de The Conscious Plant Kitchen. Roulées et gratinées.', 230),
  ('idea-orangecauli', 'Chou-fleur croustillant à l''orange', 'diner', ARRAY['diner']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 380, 10, null, null, 1, '[]'::jsonb, '🍊', false, '["1 chou-fleur en bouquets","1 c. à soupe de maïzena","sauce orange (jus d''orange, soja, ail, sirop)","60 g de riz (cru) cuit"]'::jsonb, '["Enrobe le chou-fleur de maïzena, rôtis au four 25 min.","Réduis la sauce orange.","Enrobe et sers sur le riz."]'::jsonb, 'Inspirée de The Conscious Plant Kitchen. La version légumes du tofu à l''orange.', 231),
  ('idea-oatrolls', 'Petits pains à l''avoine', 'pdj', ARRAY['pdj']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 120, 6, null, null, 1, '[]'::jsonb, '🍞', false, '["flocons d''avoine mixés","yaourt soja","levure + sel","graines (option)"]'::jsonb, '["Mélange avoine + yaourt + levure en pâte.","Forme des petits pains.","Cuis 30 min au four à 180°C."]'::jsonb, 'Inspirée de The Conscious Plant Kitchen. 6 g de protéines, 12 g de fibres, sans œuf. (par petit pain)', 232),
  ('idea-bananabars', 'Barres avoine, banane & yaourt soja', 'snack', ARRAY['snack']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 150, 5, null, null, 1, '[]'::jsonb, '🍌', false, '["2 bananes écrasées","150 g de yaourt soja","120 g de flocons d''avoine","pépites ou fruits secs (option)"]'::jsonb, '["Mélange tout.","Étale dans un moule.","Cuis 30-35 min à 180°C, coupe en barres."]'::jsonb, 'Inspirée de The Conscious Plant Kitchen. 4 ingrédients, à emporter.', 233),
  ('idea-kombuchacake', 'Gâteau au kombucha (plaisir)', 'snack', ARRAY['snack']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 250, 3, null, null, 1, '[]'::jsonb, '🍰', false, '["farine à levée incorporée (ou farine + levure)","sucre","kombucha (saveur fruits rouges ou citron)","huile neutre ou margarine fondue"]'::jsonb, '["Mélange farine + sucre, verse kombucha + huile.","Remue en pâte lisse, verse dans un moule.","Cuis ~50 min à 180°C. Laisse refroidir avant de couper."]'::jsonb, 'Inspirée de The Conscious Plant Kitchen. 4 ingrédients. Plaisir occasionnel : c''est un gâteau, le kombucha ne sert qu''à lever la pâte. (par part)', 234),
  ('idea-taboule', 'Taboulé sucré-salé tomates & abricots rôtis', 'dej', ARRAY['dej']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 400, 14, null, null, 1, '[]'::jsonb, '🍅', true, '["60 g de semoule ou boulgour (cru) cuit","tomates + abricots rôtis","100 g de pois chiches","menthe, citron, filet d''huile d''olive"]'::jsonb, '["Cuis la semoule.","Rôtis tomates et abricots 15 min.","Mélange avec pois chiches, menthe et citron."]'::jsonb, 'Inspirée de Recettes de Julie. Frais et original. J''ai ajouté des pois chiches pour les protéines.', 235),
  ('idea-nicecream', 'Nicecream banane-kiwi', 'snack', ARRAY['snack']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 150, 4, null, null, 1, '[]'::jsonb, '🍦', true, '["2 bananes congelées en rondelles","1 kiwi","option : 1/2 dose de Vegan Protein","un filet de lait d''amande"]'::jsonb, '["Mixe bananes congelées + kiwi (+ protéine si tu veux).","Ajoute un peu de lait d''amande pour la texture.","Sers aussitôt."]'::jsonb, 'Inspirée de Recettes de Julie. Glace minute sans sucre ajouté. Une dose de protéine la transforme en dessert protéiné.', 236),
  ('idea-concoyaourt', 'Salade concombre au yaourt soja', 'snack', ARRAY['snack']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 120, 8, null, null, 1, '[]'::jsonb, '🥒', true, '["1 concombre","150 g de yaourt soja nature","ail, menthe, citron","sel, poivre"]'::jsonb, '["Coupe le concombre.","Mélange yaourt soja + ail + menthe + citron.","Assaisonne et sers bien frais."]'::jsonb, 'Inspirée de Recettes de Julie (yaourt soja à la place du grec). Fraîche et protéinée pour quasi rien.', 237),
  ('idea-epeautre', 'Salade de petit épeautre', 'dej', ARRAY['dej']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 450, 16, null, null, 1, '[]'::jsonb, '🌾', false, '["70 g de petit épeautre (cru) cuit","tomates cerises, concombre, poivron","feta ou tofu fumé en dés","herbes, citron, filet d''huile d''olive"]'::jsonb, '["Cuis le petit épeautre.","Mélange avec les légumes et le fromage/tofu.","Assaisonne citron + herbes."]'::jsonb, 'Inspirée de Recettes de Julie. Grains + légumes + fromage ou tofu.', 238),
  ('idea-crepescitron', 'Crêpes citron & graines de pavot', 'pdj', ARRAY['pdj']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 300, 10, null, null, 1, '[]'::jsonb, '🍋', false, '["80 g de farine","250 ml de lait d''amande","1 œuf","zeste de citron + graines de pavot"]'::jsonb, '["Mélange farine, lait d''amande, œuf, citron, pavot.","Cuis les crêpes à la poêle.","Garnis léger : fruits ou filet de sirop."]'::jsonb, 'Inspirée de Recettes de Julie. Au lait d''amande.', 239),
  ('idea-pastapestoskyr', 'Pâtes pesto au skyr, asperges & brocolis', 'dej', ARRAY['dej']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 480, 22, null, null, 1, '[]'::jsonb, '🍝', false, '["80 g de pâtes (crues) cuites","asperges + brocolis sautés","2 c. à soupe de pesto","150 g de skyr/yaourt soja épais","citron"]'::jsonb, '["Cuis les pâtes, saute asperges et brocolis.","Hors du feu, mélange pesto + skyr soja.","Lie le tout, citron et poivre."]'::jsonb, 'Inspirée de Recettes de Julie. Le crémeux du pesto sans crème, grâce au skyr soja. Healthy et protéiné.', 240),
  ('idea-oeufscocotte', 'Œufs cocotte aux asperges', 'dej', ARRAY['dej']::text[], ARRAY[]::text[], 'recipe', 'portion', 1, 280, 16, null, null, 1, '[]'::jsonb, '🍳', false, '["2 œufs","asperges vertes","un peu de fromage","sel, poivre"]'::jsonb, '["Dispose asperges + fromage dans un ramequin.","Casse les œufs dessus.","Cuis 12-15 min au four à 180°C."]'::jsonb, 'Inspirée de Recettes de Julie. Au four, protéiné et rapide.', 241),
